import html

def escape(s: str) -> str:
    return html.escape(s, quote=False).replace('"', '&amp;quot;').replace('&lt;', '&amp;lt;').replace('&gt;', '&amp;gt;')

def unescape(s: str) -> str:
    return html.unescape(s)

